sql:
SELECT info_type, uses
FROM information_types
WHERE sensitive = 0;

SELECT name, address, card_status, last_active_date, borrowed_materials, fines, phone_number, email
FROM library_patrons
WHERE bank_id = (SELECT bank_id FROM banks WHERE bank_title = 'Financial Services – Tax Assessment Roll');

SELECT COUNT(DISTINCT r.bank_id) 
FROM retention_policies r
WHERE r.disposition_action = 'retained';

SELECT individuals.first_name, individuals.individual_type, banks.bank_title
FROM individuals
JOIN banks ON individuals.bank_id = banks.bank_id;

